import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            key = f'{name} [{fw[\"framework\"]}]'
            result[key] = {p['id']: p['resolvedVersion'] for p in fw.get('topLevelPackages', [])}
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(key, {})
    ap = a.get(key, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, '-')
        av = ap.get(pkg, '-')
        proj = key.split(' [')[0]
        if bv != av:
            changes.append((proj, pkg, bv, av))
        else:
            unchanged.append((proj, pkg, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]}: {c[1]} {c[2]} -> {c[3]}')
else:
    print('  None')

print(f'\n=== UNCHANGED: {len(unchanged)} packages ===')
for u in unchanged:
    print(f'  {u[0]}: {u[1]} {u[2]}')
"

